const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const players = new Map();
const sessions = new Map();
const SECRET_KEY = process.env.SECRET_KEY || crypto.randomBytes(32).toString('hex');

app.use(express.json());

// Secure session management
function generateSessionId() {
    return crypto.randomBytes(32).toString('hex');
}

function validateSession(sessionId) {
    if (!sessionId || !sessions.has(sessionId)) return false;
    const session = sessions.get(sessionId);
    return Date.now() < session.expires;
}

// Authentication middleware
const authenticate = (req, res, next) => {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return res.status(401).json({ error: 'Unauthorized' });
    }
    
    const token = authHeader.substring(7);
    if (!validateSession(token)) {
        return res.status(401).json({ error: 'Invalid session' });
    }
    
    next();
};

// Player registration
app.post('/register', async (req, res) => {
    try {
        const { username, password } = req.body;
        
        if (!username || !password || password.length < 6) {
            return res.status(400).json({ error: 'Invalid input' });
        }
        
        // Validate username (alphanumeric and underscores only)
        if (!/^[a-zA-Z0-9_]+$/.test(username)) {
            return res.status(400).json({ error: 'Invalid username' });
        }
        
        // Check if username exists
        if (players.has(username)) {
            return res.status(409).json({ error: 'Username taken' });
        }
        
        const hashedPassword = await bcrypt.hash(password, 12);
        players.set(username, {
            password: hashedPassword,
            createdAt: Date.now()
        });
        
        res.json({ message: 'Registered successfully' });
    } catch (error) {
        res.status(500).json({ error: 'Server error' });
    }
});

// Player login
app.post('/login', async (req, res) => {
    try {
        const { username, password } = req.body;
        
        if (!username || !password) {
            return res.status(400).json({ error: 'Missing credentials' });
        }
        
        const player = players.get(username);
        if (!player || !await bcrypt.compare(password, player.password)) {
            return res.status(401).json({ error: 'Invalid credentials' });
        }
        
        const sessionId = generateSessionId();
        const expires = Date.now() + 24 * 60 * 60 * 1000; // 24 hours
        
        sessions.set(sessionId, {
            username,
            expires
        });
        
        res.json({ token: sessionId });
    } catch (error) {
        res.status(500).json({ error: 'Server error' });
    }
});

// Secure leaderboard endpoint
app.get('/leaderboard', authenticate, (req, res) => {
    const leaderboard = Array.from(players.entries())
        .filter(([username, data]) => data.score !== undefined)
        .map(([username, data]) => ({
            username,
            score: data.score
        }))
        .sort((a, b) => b.score - a.score)
        .slice(0, 100);
    
    res.json(leaderboard);
});

io.on('connection', (socket) => {
    let currentUsername = null;
    
    socket.on('authenticate', (data, callback) => {
        if (!data.token || !validateSession(data.token)) {
            return callback({ error: 'Authentication failed' });
        }
        
        const session = sessions.get(data.token);
        currentUsername = session.username;
        socket.join(currentUsername);
        callback({ success: true });
    });
    
    socket.on('submitScore', (data, callback) => {
        if (!currentUsername || !data || typeof data.score !== 'number') {
            return callback({ error: 'Invalid data' });
        }
        
        // Store score (trust client-reported score for now)
        const player = players.get(currentUsername);
        if (player) {
            player.score = Math.max(player.score || 0, data.score);
            callback({ success: true });
        } else {
            callback({ error: 'Player not found' });
        }
    });
    
    socket.on('disconnect', () => {
        if (currentUsername) {
            socket.leave(currentUsername);
        }
    });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
});